using Microsoft.EntityFrameworkCore;
class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Blog>(b =>
        {
            // EF Core 9 renamed the default discriminator from "Discriminator" to "$type".
            // Preserve the old name so existing documents remain queryable.
            b.HasDiscriminator<string>("Discriminator");

            // EF Core 9 no longer includes the discriminator in the JSON id property.
            // Preserve "Blog|1" format so existing documents remain accessible.
            b.HasRootDiscriminatorInJsonId(true);
        });

        // Removed HasIndex: EF Core 9 Cosmos provider throws at startup.
        // Manage indexing via the Cosmos DB indexing policy instead.
    }
}

